#include "pytorch_npu_helper.hpp"

static at::Tensor conv_dw_3x3_no_pad_no_stride1_npu(const at::Tensor& x, const at::Tensor& weight) {
    TORCH_CHECK(x.dim() == 4, "x must be 4D NCHW");
    TORCH_CHECK(weight.dim() == 4, "weight must be 4D (C,1,3,3)");
    TORCH_CHECK(weight.size(1) == 1 && weight.size(2) == 3 && weight.size(3) == 3, "weight must be (C,1,3,3)");
    TORCH_CHECK(x.size(1) == weight.size(0), "in_channels must equal out_channels for depthwise multiplier=1");
    auto N = x.size(0);
    auto C = x.size(1);
    auto H = x.size(2);
    auto W = x.size(3);
    TORCH_CHECK(H >= 3 && W >= 3, "H and W must be >= 3");

    auto outH = H - 2;
    auto outW = W - 2;
    at::Tensor y = at::empty({N, C, outH, outW}, x.options());

    EXEC_NPU_CMD(aclnnConvDepthwise2dAsymmetricInputSquareKernelCustom, x, weight, y);
    return y;
}

